class DiskCache:
    """Disk-based cache with msgpack serialization and timestamp-based expiration."""

    def __init__(self, cache_dir="cache", default_ttl=300):
        self.cache_dir = cache_dir
        self.default_ttl = default_ttl
        self._lock = threading.Lock()
        os.makedirs(cache_dir, exist_ok=True)

    def _get_cache_path(self, key):
        hashed = hashlib.sha256(key.encode("utf-8")).hexdigest()
        return os.path.join(self.cache_dir, f"{hashed}.msgpack")

    def _serialize(self, data, ttl):
        entry = {
            "timestamp": time.time(),
            "ttl": ttl,
            "data": data,
        }
        return msgpack.packb(entry, use_bin_type=True)

    def _deserialize(self, raw_bytes):
        return msgpack.unpackb(raw_bytes, raw=False)

    def get(self, key):
        path = self._get_cache_path(key)
        with self._lock:
            if not os.path.exists(path):
                return None
            try:
                with open(path, "rb") as f:
                    raw = f.read()
                entry = self._deserialize(raw)
                elapsed = time.time() - entry["timestamp"]
                if elapsed > entry["ttl"]:
                    os.remove(path)
                    return None
                return entry["data"]
            except (msgpack.exceptions.UnpackException, KeyError, OSError):
                # Corrupted cache file, remove it
                if os.path.exists(path):
                    os.remove(path)
                return None

    def set(self, key, data, ttl=None):
        if ttl is None:
            ttl = self.default_ttl
        path = self._get_cache_path(key)
        serialized = self._serialize(data, ttl)
        with self._lock:
            with open(path, "wb") as f:
                f.write(serialized)

    def delete(self, key):
        path = self._get_cache_path(key)
        with self._lock:
            if os.path.exists(path):
                os.remove(path)
                return True
        return False

    def clear(self):
        with self._lock:
            for filename in os.listdir(self.cache_dir):
                if filename.endswith(".msgpack"):
                    filepath = os.path.join(self.cache_dir, filename)
                    os.remove(filepath)

    def cleanup_expired(self):
        """Remove all expired entries from the cache directory."""
        removed = 0
        with self._lock:
            for filename in os.listdir(self.cache_dir):
                if not filename.endswith(".msgpack"):
                    continue
                filepath = os.path.join(self.cache_dir, filename)
                try:
                    with open(filepath, "rb") as f:
                        entry = self._deserialize(f.read())
                    elapsed = time.time() - entry["timestamp"]
                    if elapsed > entry["ttl"]:
                        os.remove(filepath)
                        removed += 1
                except (msgpack.exceptions.UnpackException, KeyError, OSError):
                    os.remove(filepath)
                    removed += 1
        return removed

    def stats(self):
        """Return cache statistics."""
        total = 0
        expired = 0
        valid = 0
        total_size = 0
        with self._lock:
            for filename in os.listdir(self.cache_dir):
                if not filename.endswith(".msgpack"):
                    continue
                total += 1
                filepath = os.path.join(self.cache_dir, filename)
                total_size += os.path.getsize(filepath)
                try:
                    with open(filepath, "rb") as f:
                        entry = self._deserialize(f.read())
                    elapsed = time.time() - entry["timestamp"]
                    if elapsed > entry["ttl"]:
                        expired += 1
                    else:
                        valid += 1
                except (msgpack.exceptions.UnpackException, KeyError, OSError):
                    expired += 1
        return {
            "total_entries": total,
            "valid_entries": valid,
            "expired_entries": expired,
            "total_size_bytes": total_size,
        }


# Global cache instance
cache = DiskCache(cache_dir="api_cache", default_ttl=300)


def cached_route(ttl=None, key_func=None):
    """Decorator to cache Flask route responses."""
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            if key_func:
                cache_key = key_func()
            else:
                # Build cache key from request method, path, query string, and JSON body
                parts = [request.method, request.path, request.query_string.decode("utf-8")]
                if request.is_json and request.data:
                    parts.append(request.data.decode("utf-8"))
                cache_key = "|".join(parts)

            cached_data = cache.get(cache_key)
            if cached_data is not None:
                cached_data["_cache"] = "hit"
                return jsonify(cached_data)

            response_data = f(*args, **kwargs)

            if isinstance(response_data, dict):
                cache.set(cache_key, response_data, ttl=ttl)
                response_data["_cache"] = "miss"
                return jsonify(response_data)

            return response_data

        return decorated_function
    return decorator


